mapper.sql:
SELECT
ID,
CUSTOMER_CODE,
CUSTOMER_NAME,
EN_CUSTOMER_NAME,
CUSTOMER_SHORT,
REMARK,
STAUTS,
CREATE_BY,
CREATE_TIME,
UPDATE_BY,
UPDATE_TIME
FROM
M_CUSTOMER


        and ID = #{id}



        and CUSTOMER_CODE LIKE #{customerCode}



        and CUSTOMER_NAME LIKE #{customerName}


        and EN_CUSTOMER_NAME = #{enCustomerName}


        and CUSTOMER_SHORT = #{customerShort}


        and REMARK = #{remark}


        and STAUTS = #{stauts}
